import{_ as e}from"./chunks/微笑狼的公开仓库.gGdYP2E_.js";import{_ as t,o as i,c as o,a2 as s}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Etiquetado automático","description":"","frontmatter":{},"headers":[],"relativePath":"es/Other/auto-tagging.md","filePath":"es/Other/auto-tagging.md","lastUpdated":1781962217000}'),r={name:"es/Other/auto-tagging.md"};function l(n,a,d,c,p,u){return i(),o("div",null,[...a[0]||(a[0]=[s('<h1 id="etiquetado-automatico" tabindex="-1">Etiquetado automático <a class="header-anchor" href="#etiquetado-automatico" aria-label="Permalink to &quot;Etiquetado automático&quot;">​</a></h1><p>El etiquetado automático se configura en:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Configuración del sistema -&gt; Otros ajustes -&gt; Etiquetado automático</span></span></code></pre></div><p>Esta función genera etiquetas para las imágenes y facilita la búsqueda, los filtros de la API aleatoria, la galería pública y el control de acceso por clasificación de edad.</p><h2 id="que-puede-hacer" tabindex="-1">Qué puede hacer <a class="header-anchor" href="#que-puede-hacer" aria-label="Permalink to &quot;Qué puede hacer&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Función</th><th>Descripción</th></tr></thead><tbody><tr><td>Etiquetas de contenido</td><td>Añade etiquetas de personas, escenas, objetos, estilo visual y más</td></tr><tr><td>Etiquetas de personajes</td><td>Útil para imágenes de anime e ilustraciones</td></tr><tr><td>Etiquetas de orientación</td><td>Añade <code>landscape</code>, <code>portrait</code> o <code>square</code></td></tr><tr><td>Clasificación de imagen</td><td>Guarda resultados <code>G/S/Q/E</code></td></tr><tr><td>Etiquetar al subir</td><td>Procesa automáticamente las imágenes nuevas</td></tr><tr><td>Etiquetado por lotes</td><td>Añade etiquetas a imágenes antiguas en una o varias carpetas</td></tr></tbody></table><h2 id="que-preparar-primero" tabindex="-1">Qué preparar primero <a class="header-anchor" href="#que-preparar-primero" aria-label="Permalink to &quot;Qué preparar primero&quot;">​</a></h2><p>Necesitas al menos una URL accesible de Hugging Face Space.</p><p>Lo recomendable es duplicar el Space <code>wd-tagger</code> de SmilingWolf en tu propia cuenta de Hugging Face:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><p>Puedes usar el Space público para pruebas, pero lo comparten muchos usuarios y puede tener cola, ir lento o quedar no disponible. Para uso continuo conviene tener una copia propia.</p><h2 id="duplicar-el-space" tabindex="-1">Duplicar el Space <a class="header-anchor" href="#duplicar-el-space" aria-label="Permalink to &quot;Duplicar el Space&quot;">​</a></h2><ol><li>Inicia sesión en Hugging Face.</li><li>Abre <code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code>.</li></ol><p><img src="'+e+`" alt="Space público de SmilingWolf" loading="lazy"></p><ol start="3"><li>Abre el menú de la esquina superior derecha.</li><li>Elige <code>Duplicate this Space</code>.</li><li>Mantén el nombre o usa uno reconocible, como <code>wd-tagger</code>.</li><li>Déjalo como <code>Public</code>; así ImgBed puede llamarlo con menos fricción.</li><li>Empieza con el hardware gratuito.</li><li>Crea el Space y espera a que termine la compilación.</li></ol><p>Cuando termine, copia la URL del navegador y pégala en <code>Space URLs</code> dentro de ImgBed.</p><h2 id="ajustes-recomendados" tabindex="-1">Ajustes recomendados <a class="header-anchor" href="#ajustes-recomendados" aria-label="Permalink to &quot;Ajustes recomendados&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Opción</th><th>Recomendación</th></tr></thead><tbody><tr><td><code>Space URLs</code></td><td>Una URL por línea</td></tr><tr><td>Carpeta objetivo</td><td>Vacío para todas; selecciona una carpeta si quieres limitarlo</td></tr><tr><td>Modelo</td><td>Mantén <code>wd-swinv2-tagger-v3</code> al principio</td></tr><tr><td>Umbral de etiquetas generales</td><td>Empieza cerca de <code>0.35</code></td></tr><tr><td>Umbral de personajes</td><td>Empieza cerca de <code>0.85</code> para evitar falsos positivos</td></tr><tr><td><code>MCut</code></td><td>Déjalo apagado al principio</td></tr><tr><td>Etiquetar al subir</td><td>Actívalo si quieres procesar nuevas imágenes automáticamente</td></tr></tbody></table><p>Si salen demasiadas etiquetas, sube un poco el umbral general. Si salen muy pocas, bájalo ligeramente.</p><h2 id="etiquetado-por-lotes" tabindex="-1">Etiquetado por lotes <a class="header-anchor" href="#etiquetado-por-lotes" aria-label="Permalink to &quot;Etiquetado por lotes&quot;">​</a></h2><ol><li>Rellena <code>Space URLs</code>.</li><li>Selecciona una carpeta objetivo.</li><li>Inicia el etiquetado.</li><li>Espera a que termine el progreso.</li></ol><p>Si la carpeta objetivo queda vacía, ImgBed procesa todas las carpetas.</p><h2 id="etiquetar-al-subir" tabindex="-1">Etiquetar al subir <a class="header-anchor" href="#etiquetar-al-subir" aria-label="Permalink to &quot;Etiquetar al subir&quot;">​</a></h2><p>Cuando esta opción está activa, las imágenes nuevas llaman automáticamente a los <code>Space URLs</code> configurados.</p><p>Si el Space tiene cola, la subida puede terminar primero y el etiquetado continuar después en segundo plano.</p><h2 id="preguntas-habituales" tabindex="-1">Preguntas habituales <a class="header-anchor" href="#preguntas-habituales" aria-label="Permalink to &quot;Preguntas habituales&quot;">​</a></h2><h3 id="¿por-que-duplicar-mi-propio-space" tabindex="-1">¿Por qué duplicar mi propio Space? <a class="header-anchor" href="#¿por-que-duplicar-mi-propio-space" aria-label="Permalink to &quot;¿Por qué duplicar mi propio Space?&quot;">​</a></h3><p>Los Spaces públicos se comparten entre muchos usuarios. Una copia propia suele ser más rápida y estable para tu sitio.</p><h3 id="¿por-que-las-etiquetas-estan-en-ingles" tabindex="-1">¿Por qué las etiquetas están en inglés? <a class="header-anchor" href="#¿por-que-las-etiquetas-estan-en-ingles" aria-label="Permalink to &quot;¿Por qué las etiquetas están en inglés?&quot;">​</a></h3><p>Es normal. Los modelos de SmilingWolf devuelven etiquetas en inglés. ImgBed las usa para búsqueda, filtros, API aleatoria y galería pública.</p><h3 id="¿para-que-sirve-la-clasificacion" tabindex="-1">¿Para qué sirve la clasificación? <a class="header-anchor" href="#¿para-que-sirve-la-clasificacion" aria-label="Permalink to &quot;¿Para qué sirve la clasificación?&quot;">​</a></h3><p>La clasificación trabaja con el modo de acceso de seguridad. Por ejemplo, si limitas lo que pueden ver los visitantes por edad, la galería y la API aleatoria filtrarán según esas reglas.</p><h2 id="flujo-rapido" tabindex="-1">Flujo rápido <a class="header-anchor" href="#flujo-rapido" aria-label="Permalink to &quot;Flujo rápido&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Iniciar sesión en Hugging Face</span></span>
<span class="line"><span>-&gt; Abrir SmilingWolf/wd-tagger</span></span>
<span class="line"><span>-&gt; Duplicar el Space</span></span>
<span class="line"><span>-&gt; Esperar la compilación</span></span>
<span class="line"><span>-&gt; Copiar la URL del Space</span></span>
<span class="line"><span>-&gt; Pegarla en Space URLs</span></span>
<span class="line"><span>-&gt; Ajustar modelo y umbrales</span></span>
<span class="line"><span>-&gt; Iniciar etiquetado o activar etiquetado al subir</span></span></code></pre></div>`,34)])])}const b=t(r,[["render",l]]);export{m as __pageData,b as default};
